/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across all channels.
 * Supports per-channel enable/disable and per-channel category subscriptions.
 *
 * History: Originally email-only (Session 3). Refactored to multi-channel
 * after SMS (Session 8) and webhook support were added.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

/**
 * How frequently email notifications are delivered.
 * - 'immediate': send as soon as the event occurs
 * - 'daily-digest': batch into a daily summary
 * - 'weekly-digest': batch into a weekly summary
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * Per-channel configuration for a notification channel.
 */
export interface ChannelPreference {
  /** Whether this channel is enabled */
  enabled: boolean;
  /** Per-category subscription settings for this channel — true means subscribed */
  categorySubscriptions: Record<NotificationType, boolean>;
}

/**
 * Email-specific channel preference with frequency support.
 */
export interface EmailChannelPreference extends ChannelPreference {
  /** How often email notifications are delivered */
  frequency: EmailFrequency;
}

/**
 * Per-user notification preferences.
 */
export interface UserPreferences {
  id: string;
  /** The user this preferences record belongs to */
  userId: string;
  /** Master switch for all email notifications (backward compat) */
  emailEnabled: boolean;
  /** How often email notifications are delivered (backward compat) */
  emailFrequency: EmailFrequency;
  /** Per-category subscription settings — shared defaults (backward compat) */
  categorySubscriptions: Record<NotificationType, boolean>;
  /** Per-channel preference overrides */
  channels: Partial<Record<NotificationChannel, ChannelPreference | EmailChannelPreference>>;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for per-channel preferences when creating/updating.
 */
export interface ChannelPreferenceInput {
  enabled?: boolean;
  categorySubscriptions?: Partial<Record<NotificationType, boolean>>;
}

/**
 * Email-specific channel preference input.
 */
export interface EmailChannelPreferenceInput extends ChannelPreferenceInput {
  frequency?: EmailFrequency;
}

/**
 * Input for creating preferences (userId required, rest optional with defaults).
 */
export interface CreatePreferencesInput {
  userId: string;
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  categorySubscriptions?: Partial<Record<NotificationType, boolean>>;
  channels?: {
    email?: EmailChannelPreferenceInput;
    sms?: ChannelPreferenceInput;
    webhook?: ChannelPreferenceInput;
    'in-app'?: ChannelPreferenceInput;
  };
}

/**
 * Input for updating existing preferences.
 */
export interface UpdatePreferencesInput {
  emailEnabled?: boolean;
  emailFrequency?: EmailFrequency;
  categorySubscriptions?: Partial<Record<NotificationType, boolean>>;
  channels?: {
    email?: EmailChannelPreferenceInput;
    sms?: ChannelPreferenceInput;
    webhook?: ChannelPreferenceInput;
    'in-app'?: ChannelPreferenceInput;
  };
}

/**
 * Default category subscriptions — all enabled by default.
 */
export const defaultCategorySubscriptions: Record<NotificationType, boolean> = {
  'order-confirmation': true,
  'order-status-update': true,
  'user-welcome': true,
  'user-profile-update': true,
  'system-alert': true,
};

/**
 * Build default channel preferences for a given channel.
 */
export function defaultChannelPreference(channel: NotificationChannel): ChannelPreference | EmailChannelPreference {
  const base: ChannelPreference = {
    enabled: true,
    categorySubscriptions: { ...defaultCategorySubscriptions },
  };
  if (channel === 'email') {
    return { ...base, frequency: 'immediate' as EmailFrequency };
  }
  return base;
}

