/**
 * Check whether a notification should be sent to a user on a given channel.
 * Uses per-channel preferences if set, falls back to legacy email fields for 'email' channel,
 * and defaults to enabled for channels without explicit preferences.
 */
shouldSend(channel: NotificationChannel, userId: string, notificationType: NotificationType): boolean {
  const prefs = this.repository.findByUserId(userId);

  // No preferences = use defaults (all enabled)
  if (!prefs) {
    return true;
  }

  // Check per-channel preferences first
  const channelPref = prefs.channels[channel];
  if (channelPref) {
    if (!channelPref.enabled) {
      return false;
    }
    const subscribed = channelPref.categorySubscriptions[notificationType];
    return subscribed !== false;
  }

  // Fallback for email: use legacy fields for backward compatibility
  if (channel === 'email') {
    if (!prefs.emailEnabled) {
      return false;
    }
    const subscribed = prefs.categorySubscriptions[notificationType];
    return subscribed !== false;
  }

  // No channel-specific preferences and not email — default to enabled,
  // still check shared category subscriptions
  const subscribed = prefs.categorySubscriptions[notificationType];
  return subscribed !== false;
}

