describe('shouldSend (multi-channel)', () => {
  it('should return true for SMS when no preferences exist', () => {
    expect(service.shouldSend('sms', 'user-1', 'order-confirmation')).toBe(true);
  });

  it('should return true for webhook when no preferences exist', () => {
    expect(service.shouldSend('webhook', 'user-1', 'order-confirmation')).toBe(true);
  });

  it('should respect per-channel SMS enabled setting', () => {
    service.create({
      userId: 'user-1',
      channels: { sms: { enabled: false } },
    });
    expect(service.shouldSend('sms', 'user-1', 'order-confirmation')).toBe(false);
  });

  it('should respect per-channel webhook enabled setting', () => {
    service.create({
      userId: 'user-1',
      channels: { webhook: { enabled: false } },
    });
    expect(service.shouldSend('webhook', 'user-1', 'order-confirmation')).toBe(false);
  });

  it('should allow disabling SMS while keeping email enabled', () => {
    service.create({
      userId: 'user-1',
      channels: { sms: { enabled: false } },
    });
    expect(service.shouldSend('email', 'user-1', 'order-confirmation')).toBe(true);
    expect(service.shouldSend('sms', 'user-1', 'order-confirmation')).toBe(false);
  });

  it('should respect per-channel category subscriptions for SMS', () => {
    service.create({
      userId: 'user-1',
      channels: {
        sms: {
          enabled: true,
          categorySubscriptions: { 'order-confirmation': false },
        },
      },
    });
    expect(service.shouldSend('sms', 'user-1', 'order-confirmation')).toBe(false);
    expect(service.shouldSend('sms', 'user-1', 'order-status-update')).toBe(true);
  });

  it('should use per-channel email preferences over legacy fields', () => {
    service.create({
      userId: 'user-1',
      emailEnabled: true, // legacy says enabled
      channels: {
        email: { enabled: false }, // channel pref says disabled
      },
    });
    // Per-channel preference takes precedence
    expect(service.shouldSend('email', 'user-1', 'order-confirmation')).toBe(false);
  });

  it('should fall back to shared category subscriptions for channels without specific prefs', () => {
    service.create({
      userId: 'user-1',
      categorySubscriptions: { 'order-confirmation': false },
    });
    // SMS has no channel-specific prefs, so falls back to shared
    expect(service.shouldSend('sms', 'user-1', 'order-confirmation')).toBe(false);
    expect(service.shouldSend('sms', 'user-1', 'order-status-update')).toBe(true);
  });

  it('should update per-channel preferences', () => {
    service.create({
      userId: 'user-1',
      channels: { sms: { enabled: true } },
    });
    service.update('user-1', {
      channels: { sms: { enabled: false } },
    });
    expect(service.shouldSend('sms', 'user-1', 'order-confirmation')).toBe(false);
  });

  it('should merge channel category subscriptions on update', () => {
    service.create({
      userId: 'user-1',
      channels: {
        sms: {
          enabled: true,
          categorySubscriptions: { 'order-confirmation': true },
        },
      },
    });
    service.update('user-1', {
      channels: {
        sms: {
          categorySubscriptions: { 'order-confirmation': false },
        },
      },
    });
    expect(service.shouldSend('sms', 'user-1', 'order-confirmation')).toBe(false);
  });
});

