describe('NotificationService multi-channel preferences', () => {
  let eventBus: EventBus;
  let service: NotificationService;
  let preferencesService: PreferencesService;
  let smsAdapter: SmsAdapter;
  let webhookAdapter: WebhookAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    service = new NotificationService(eventBus);
    service.registerAdapter(new EmailAdapter());
    smsAdapter = new SmsAdapter();
    service.registerAdapter(smsAdapter);
    webhookAdapter = new WebhookAdapter();
    service.registerAdapter(webhookAdapter);

    const db = new Database();
    const prefsRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(prefsRepo);
    service.setPreferencesService(preferencesService);

    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should suppress SMS when SMS channel is disabled', async () => {
    preferencesService.create({
      userId: '+15551234567',
      channels: { sms: { enabled: false } },
    });

    const result = await service.send({
      recipient: '+15551234567',
      subject: 'Order shipped',
      body: 'Your order has shipped',
      channel: 'sms',
      type: 'order-status-update',
      priority: 'normal',
    });

    expect(result.status).toBe('suppressed');
  });

  it('should send SMS when SMS channel is enabled', async () => {
    preferencesService.create({
      userId: '+15551234567',
      channels: { sms: { enabled: true } },
    });

    const result = await service.send({
      recipient: '+15551234567',
      subject: 'Order shipped',
      body: 'Your order has shipped',
      channel: 'sms',
      type: 'order-status-update',
      priority: 'normal',
    });

    expect(result.status).toBe('sent');
  });

  it('should suppress webhook when webhook channel is disabled', async () => {
    preferencesService.create({
      userId: 'https://example.com/hook',
      channels: { webhook: { enabled: false } },
    });

    const result = await service.send({
      recipient: 'https://example.com/hook',
      subject: 'System Alert',
      body: 'CPU usage high',
      channel: 'webhook',
      type: 'system-alert',
      priority: 'high',
    });

    expect(result.status).toBe('suppressed');
  });

  it('should suppress SMS for a specific category while allowing others', async () => {
    preferencesService.create({
      userId: '+15551234567',
      channels: {
        sms: {
          enabled: true,
          categorySubscriptions: { 'order-confirmation': false },
        },
      },
    });

    const suppressed = await service.send({
      recipient: '+15551234567',
      subject: 'Order confirmed',
      body: 'Your order is confirmed',
      channel: 'sms',
      type: 'order-confirmation',
      priority: 'normal',
    });
    expect(suppressed.status).toBe('suppressed');

    const sent = await service.send({
      recipient: '+15551234567',
      subject: 'Order shipped',
      body: 'Your order has shipped',
      channel: 'sms',
      type: 'order-status-update',
      priority: 'normal',
